var atmState = ATM_IDLE;

ATM() = 
  if (atmState == ATM_IDLE) {
    card_insert{atmState = ATM_CARD_INSERTED;} -> ATM()
  } else if (atmState == ATM_CARD_INSERTED) {
    (pin_input{atmState = ATM_PROCESSING;} -> ATM()) timeout[TIMEOUT_DURATION] (eject_card{atmState = ATM_TIMEOUT_EJECT;} -> ATM())
  } else if (atmState == ATM_PROCESSING) {
    transaction_complete{atmState = ATM_IDLE;} -> ATM()
  } else if (atmState == ATM_TIMEOUT_EJECT) {
    card_ejected{atmState = ATM_IDLE;} -> ATM()
  } else {
    Stop
  };

User() = 
  card_insert -> (pin_input -> User()) timeout[TIMEOUT_DURATION] (Stop);

System() = ATM() || User();

#define card_ejected (atmState == ATM_TIMEOUT_EJECT);

#assert System() deadlockfree;
#assert System() reaches card_ejected;

